const l="",i="";async function r(){const e=document.getElementById("nodes-list");try{const t=await fetch(`${l}/jsonapi/node/basic_page_layout_builder`);if(!t.ok)throw new Error(`HTTP ${t.status}`);const{data:s}=await t.json();e.innerHTML=s.length?s.map(o=>`<li>${o.attributes.title}</li>`).join(""):'<li style="color:#999">No content found.</li>'}catch(t){e.innerHTML=`<li style="color:#c00">Could not load Drupal content: ${t.message}</li>`}}async function a(){const e=document.getElementById("submissions-list");try{const t=await fetch(`${i}/api/submissions`);if(!t.ok)throw new Error(`HTTP ${t.status}`);const s=await t.json();e.innerHTML=s.length?s.map(o=>`<li>
                  <strong>${o.name}</strong>: ${o.message}
                  <small style="color:#999; margin-left: 0.5rem;">${o.created_at}</small>
                </li>`).join(""):'<li style="color:#999">No submissions yet.</li>'}catch(t){e.innerHTML=`<li style="color:#c00">Could not load submissions: ${t.message}</li>`}}document.getElementById("submission-form").addEventListener("submit",async e=>{e.preventDefault();const t=document.getElementById("form-status"),s=document.getElementById("name").value.trim(),o=document.getElementById("message").value.trim();t.style.color="#666",t.textContent="Submitting…";try{const n=await fetch(`${i}/api/submissions`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({name:s,message:o})});if(!n.ok)throw new Error(`HTTP ${n.status}`);t.style.color="#060",t.textContent="Submitted!",e.target.reset(),a(),setTimeout(()=>{t.textContent=""},3e3)}catch(n){t.style.color="#c00",t.textContent=`Error: ${n.message}`}});r();a();